; RawrXD_PE_Writer_Test.asm\n; Test and demonstration of the completed import table implementation\n; Shows how to create a complete PE executable with proper import tables\n\nOPTION CASEMAP:NONE\n\n; Include the PE Writer (would be assembled separately)\nEXTERN PEWriter_CreateExecutable: PROC\nEXTERN PEWriter_AddImport: PROC\nEXTERN PEWriter_AddCode: PROC\nEXTERN PEWriter_WriteFile: PROC\n\n; Windows API functions for testing\nEXTERN ExitProcess: PROC\nEXTERN GetStdHandle: PROC\nEXTERN WriteConsoleA: PROC\n\n.data\n; Test strings for import table\nkernel32_dll    db \"kernel32.dll\", 0\nuser32_dll      db \"user32.dll\", 0\nntdll_dll       db \"ntdll.dll\", 0\n\n; Kernel32 function names\nExitProcess_name        db \"ExitProcess\", 0\nGetProcessHeap_name     db \"GetProcessHeap\", 0\nHeapAlloc_name          db \"HeapAlloc\", 0\nHeapFree_name           db \"HeapFree\", 0\nCreateFileA_name        db \"CreateFileA\", 0\nWriteFile_name          db \"WriteFile\", 0\nCloseHandle_name        db \"CloseHandle\", 0\nGetStdHandle_name       db \"GetStdHandle\", 0\n\n; User32 function names  \nMessageBoxA_name        db \"MessageBoxA\", 0\nFindWindowA_name        db \"FindWindowA\", 0\nGetWindowTextA_name     db \"GetWindowTextA\", 0\n\n; NTDLL function names\nNtQueryInformationProcess_name db \"NtQueryInformationProcess\", 0\nRtlInitUnicodeString_name      db \"RtlInitUnicodeString\", 0\n\n; Output filename\noutput_exe      db \"test_output.exe\", 0\n\n; Test status messages\nmsg_start       db \"Starting PE Writer Import Table Test...\", 13, 10, 0\nmsg_create      db \"Creating PE context...\", 13, 10, 0\nmsg_kernel32    db \"Adding kernel32.dll imports...\", 13, 10, 0\nmsg_user32      db \"Adding user32.dll imports...\", 13, 10, 0\nmsg_ntdll       db \"Adding ntdll.dll imports...\", 13, 10, 0\nmsg_code        db \"Adding test code...\", 13, 10, 0\nmsg_write       db \"Writing PE file...\", 13, 10, 0\nmsg_success     db \"PE file generated successfully!\", 13, 10, 0\nmsg_error       db \"Error occurred during PE generation!\", 13, 10, 0\n\n; Simple test code (Hello World function)\ntest_code_data  LABEL BYTE\n    ; Windows x64 calling convention test code\n    ; sub rsp, 28h                 ; Shadow space + alignment\n    db 48h, 83h, 0ECh, 28h\n    ; mov rcx, -11                 ; STD_OUTPUT_HANDLE\n    db 48h, 0C7h, 0C1h, 0F5h, 0FFh, 0FFh, 0FFh\n    ; call GetStdHandle (would be resolved by import table)\n    db 0E8h, 0, 0, 0, 0          ; Placeholder call\n    ; mov rcx, rax                 ; Handle to stdout\n    db 48h, 89h, 0C1h\n    ; lea rdx, [hello_msg]         ; Message buffer\n    db 48h, 8Dh, 15h, 20h, 0, 0, 0  ; Placeholder LEA\n    ; mov r8, 13                   ; Message length\n    db 49h, 0C7h, 0C0h, 0Dh, 0, 0, 0\n    ; lea r9, [bytes_written]      ; Bytes written\n    db 4Ch, 8Dh, 0Dh, 30h, 0, 0, 0  ; Placeholder LEA\n    ; mov qword ptr [rsp+20h], 0   ; Console mode\n    db 48h, 0C7h, 44h, 24h, 20h, 0, 0, 0, 0\n    ; call WriteConsoleA (would be resolved by import table)\n    db 0E8h, 0, 0, 0, 0          ; Placeholder call\n    ; xor rcx, rcx                 ; Exit code 0\n    db 48h, 31h, 0C9h\n    ; call ExitProcess (would be resolved by import table)\n    db 0E8h, 0, 0, 0, 0          ; Placeholder call\n    ; Hello World message\n    db \"Hello, World!\", 13, 10\n    ; Placeholder for bytes_written\n    dd 0\ntest_code_size  equ $ - test_code_data\n\n.code\n\n;-----------------------------------------------------------------------------\n; PrintMessage - Simple console output for test status\n; Input: RCX = message string\n;-----------------------------------------------------------------------------\nPrintMessage PROC\n    push rbp\n    mov rbp, rsp\n    sub rsp, 40h\n    push rbx\n    push rsi\n    \n    mov rsi, rcx     ; Save message\n    \n    ; Get stdout handle\n    mov rcx, -11     ; STD_OUTPUT_HANDLE\n    call GetStdHandle\n    mov rbx, rax     ; Save handle\n    \n    ; Calculate message length\n    mov rcx, rsi\n    call strlen\n    \n    ; Write message\n    mov rcx, rbx     ; Handle\n    mov rdx, rsi     ; Message\n    mov r8, rax      ; Length\n    lea r9, [rsp+60h] ; Bytes written (placeholder)\n    mov qword ptr [rsp+20h], 0\n    call WriteConsoleA\n    \n    pop rsi\n    pop rbx\n    add rsp, 40h\n    pop rbp\n    ret\nPrintMessage ENDP\n\n;-----------------------------------------------------------------------------\n; strlen - Calculate string length\n; Input: RCX = string\n; Output: RAX = length\n;-----------------------------------------------------------------------------\nstrlen PROC\n    push rcx\n    xor rax, rax\nstrlen_loop:\n    cmp byte ptr [rcx], 0\n    je strlen_done\n    inc rcx\n    inc rax\n    jmp strlen_loop\nstrlen_done:\n    pop rcx\n    ret\nstrlen ENDP\n\n;-----------------------------------------------------------------------------\n; TestImportTableGeneration - Main test function\n; Demonstrates complete import table functionality\n;-----------------------------------------------------------------------------\nTestImportTableGeneration PROC\n    push rbp\n    mov rbp, rsp\n    sub rsp, 40h\n    push rbx\n    push rsi\n    push rdi\n    \n    ; Print start message\n    lea rcx, msg_start\n    call PrintMessage\n    \n    ; Create PE context\n    lea rcx, msg_create\n    call PrintMessage\n    \n    call PEWriter_CreateExecutable\n    test rax, rax\n    jz test_error\n    mov rdi, rax     ; Save PE context\n    \n    ; Add kernel32.dll imports (multiple functions from same DLL)\n    lea rcx, msg_kernel32\n    call PrintMessage\n    \n    mov rcx, rdi\n    lea rdx, kernel32_dll\n    lea r8, ExitProcess_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    mov rcx, rdi\n    lea rdx, kernel32_dll        ; Same DLL - should be deduplicated\n    lea r8, GetProcessHeap_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    mov rcx, rdi\n    lea rdx, kernel32_dll        ; Same DLL - should be deduplicated\n    lea r8, HeapAlloc_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    mov rcx, rdi\n    lea rdx, kernel32_dll        ; Same DLL - should be deduplicated\n    lea r8, HeapFree_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    mov rcx, rdi\n    lea rdx, kernel32_dll        ; Same DLL - should be deduplicated\n    lea r8, CreateFileA_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    mov rcx, rdi\n    lea rdx, kernel32_dll        ; Same DLL - should be deduplicated\n    lea r8, WriteFile_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    mov rcx, rdi\n    lea rdx, kernel32_dll        ; Same DLL - should be deduplicated\n    lea r8, CloseHandle_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    mov rcx, rdi\n    lea rdx, kernel32_dll        ; Same DLL - should be deduplicated\n    lea r8, GetStdHandle_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    ; Add user32.dll imports (different DLL)\n    lea rcx, msg_user32\n    call PrintMessage\n    \n    mov rcx, rdi\n    lea rdx, user32_dll          ; Different DLL - new descriptor\n    lea r8, MessageBoxA_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    mov rcx, rdi\n    lea rdx, user32_dll          ; Same as above - should be deduplicated\n    lea r8, FindWindowA_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    mov rcx, rdi\n    lea rdx, user32_dll          ; Same as above - should be deduplicated\n    lea r8, GetWindowTextA_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    ; Add ntdll.dll imports (third DLL)\n    lea rcx, msg_ntdll\n    call PrintMessage\n    \n    mov rcx, rdi\n    lea rdx, ntdll_dll           ; Third DLL - new descriptor\n    lea r8, NtQueryInformationProcess_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    mov rcx, rdi\n    lea rdx, ntdll_dll           ; Same as above - should be deduplicated\n    lea r8, RtlInitUnicodeString_name\n    call PEWriter_AddImport\n    test rax, rax\n    jz test_error\n    \n    ; Add test code\n    lea rcx, msg_code\n    call PrintMessage\n    \n    mov rcx, rdi\n    lea rdx, test_code_data\n    mov r8, test_code_size\n    call PEWriter_AddCode\n    test rax, rax\n    jz test_error\n    \n    ; Write PE file\n    lea rcx, msg_write\n    call PrintMessage\n    \n    mov rcx, rdi\n    lea rdx, output_exe\n    call PEWriter_WriteFile\n    test rax, rax\n    jz test_error\n    \n    ; Success\n    lea rcx, msg_success\n    call PrintMessage\n    jmp test_done\n    \ntest_error:\n    lea rcx, msg_error\n    call PrintMessage\n    \ntest_done:\n    pop rdi\n    pop rsi\n    pop rbx\n    add rsp, 40h\n    pop rbp\n    ret\nTestImportTableGeneration ENDP\n\n;-----------------------------------------------------------------------------\n; Main entry point\n;-----------------------------------------------------------------------------\nmain PROC\n    sub rsp, 28h\n    \n    call TestImportTableGeneration\n    \n    xor rcx, rcx\n    call ExitProcess\n    \nmain ENDP\n\nEND\n\n; Expected Import Table Structure:\n; \n; Import Descriptors:\n; [0] kernel32.dll descriptor (8 functions)\n; [1] user32.dll descriptor (3 functions)\n; [2] ntdll.dll descriptor (2 functions)\n; [3] null terminator\n;\n; String Table:\n; \"kernel32.dll\\0user32.dll\\0ntdll.dll\\0\"\n;\n; Import-by-Name Structures:\n; Hint:0 \"ExitProcess\\0\"\n; Hint:1 \"GetProcessHeap\\0\"\n; Hint:2 \"HeapAlloc\\0\"\n; Hint:3 \"HeapFree\\0\"\n; Hint:4 \"CreateFileA\\0\"\n; Hint:5 \"WriteFile\\0\"\n; Hint:6 \"CloseHandle\\0\"\n; Hint:7 \"GetStdHandle\\0\"\n; Hint:8 \"MessageBoxA\\0\"\n; Hint:9 \"FindWindowA\\0\"\n; Hint:10 \"GetWindowTextA\\0\"\n; Hint:11 \"NtQueryInformationProcess\\0\"\n; Hint:12 \"RtlInitUnicodeString\\0\"\n;\n; Import Address Table (IAT):\n; [kernel32 functions] [NULL] [user32 functions] [NULL] [ntdll functions] [NULL]\n;\n; Import Lookup Table (ILT):\n; [kernel32 functions] [NULL] [user32 functions] [NULL] [ntdll functions] [NULL]\n